    int clumsy(int n) {
        if (n == 1) return 1;
        if (n == 2) return 2;
        if (n == 3) return 6;
        if (n == 4) return 7;
        int res = n * (n - 1) / (n - 2) + (n - 3);
        n -= 4;
        while (n >= 4) {
            res -= n * (n - 1) / (n - 2) - (n - 3);
            n -= 4;
        }
        if (n == 3) res -= 6;
        else if (n == 2) res -= 2;
        else if (n == 1) res -= 1;
        return res;
    }
};
